// // This module implements a 4-bit binary counter with asynchronous reset.
module four_bit_counter (
    input clk,
    input rst,
    output reg [3:0] out
);

always @(posedge clk) begin
    if (rst) begin
        out <= 4'b0000;
    end else begin
        out <= out + 1;
    end
end

endmodule
